# Bicep: define a custom role
targetScope = 'subscription'

resource vmOperatorRole 'Microsoft.Authorization/roleDefinitions@2022-04-01' = {
  name: guid(subscription().id, 'VM Operator')
  properties: {
    roleName: 'VM Operator'
    description: 'Can start, stop, and restart VMs'
    type: 'CustomRole'
    permissions: [
      {
        actions: [
          'Microsoft.Compute/virtualMachines/start/action'
          'Microsoft.Compute/virtualMachines/powerOff/action'
          'Microsoft.Compute/virtualMachines/restart/action'
          'Microsoft.Compute/virtualMachines/read'
          'Microsoft.Resources/subscriptions/resourceGroups/read'
        ]
        notActions: []
        dataActions: []
        notDataActions: []
      }
    ]
    assignableScopes: [
      subscription().id
    ]
  }
}

# Bicep: assign the custom role to a managed identity
resource roleAssignment 'Microsoft.Authorization/roleAssignments@2022-04-01' = {
  name: guid(resourceGroup().id, vmManagedIdentity.id, vmOperatorRole.id)
  properties: {
    roleDefinitionId: vmOperatorRole.id
    principalId: vmManagedIdentity.properties.principalId
    principalType: 'ServicePrincipal'
  }
}

